static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    const gert::Shape* x_shape = context->GetInputShape(0);
    const gert::Shape* h0_shape = context->GetInputShape(1);
    const gert::Shape* w_i2h_shape = context->GetInputShape(2);
    const gert::Shape* w_h2o_shape = context->GetInputShape(4);

    uint32_t totalT = static_cast<uint32_t>(x_shape->GetDim(0));
    uint32_t B     = static_cast<uint32_t>(x_shape->GetDim(1));
    uint32_t I     = static_cast<uint32_t>(x_shape->GetDim(2));
    uint32_t H     = static_cast<uint32_t>(h0_shape->GetDim(1));
    uint32_t K     = static_cast<uint32_t>(w_i2h_shape->GetDim(1));
    uint32_t O     = static_cast<uint32_t>(w_h2o_shape->GetDim(0));

    uint32_t tileH = 32;
    uint32_t tileO = 64;

    uint32_t blockDim = B;
    if (blockDim > 24) blockDim = 24;
    if (blockDim < 1) blockDim = 1;
    uint32_t batchChunk = (B + blockDim - 1) / blockDim;
    if (batchChunk < 1) batchChunk = 1;

    context->SetBlockDim(blockDim);

    tiling.set_totalT(totalT);
    tiling.set_B(B);
    tiling.set_H(H);
    tiling.set_I(I);
    tiling.set_O(O);
    tiling.set_K(K);
    tiling.set_blockDim(blockDim);
    tiling.set_batchChunk(batchChunk);
    tiling.set_tileH(tileH);
    tiling.set_tileO(tileO);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

